INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (1697, 198183, 12, 2068, '说什么好呢？', '说好了，分手后就不再联系，断绝一切联系，也不再去她的家，因为她的电脑出了问题，结果我还是去了。去了，走在回来已经熟悉的不能再熟悉的老路上，结果又是一阵阵难过。没想到、真的真的没想到短短的一年时间让自己改变了这么多，自己似乎也老了许多，对于她我又能说什么好呢？也许一开始就是我的错，也许就像旁人所说，我们之间的差距太大，是不可能在一起的。当爱情降临的时候，就像滚滚海潮，挡都挡不住，可当爱情悄悄离我而去的时候，连上帝都无可奈何。说什么好呢？现在的她已经是别人的女朋友了！说什么好呢？从这周开始去好好作弥撒把，也让自己的心好好的得到些平静把！', '说好了，分手后就不再联系，断绝一切联系，也不再去她的家，因为她的电脑出了问题，结果我还是去了。去了，走在回来已经熟悉的不能再熟悉的老路上，结果又是一阵阵难过。没想到、真的真的没想到短短的一年时间让自己改变了这么多，自己似乎也老了许多，对于她我又能说什么好呢？也许一开始就是我的错，也许就像旁人所说，我们之间的差距太大，是不可能在一起的。当爱情降临的时候，就像滚滚海潮，挡都挡不住，可当爱情悄悄离我而去的时候，连上帝都无可奈何。说什么好呢？现在的她已经是别人的女朋友了！说什么好呢？从这周开始去好好作弥撒把，也让自己的心好好的得到些平静把！', NULL, '2003-03-13 03:19:00', 1, '20030421182800_bbsid_198183_board_12_ef4bc4f827.html', '20030421182800');
